import{_ as o,o as a,c as e,a3 as l}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"工具调用测试","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/tool-calling.md","filePath":"user-guide/tools/tool-calling.md","lastUpdated":1778221347000}'),r={name:"user-guide/tools/tool-calling.md"};function n(s,t,i,d,c,h){return a(),e("div",null,[...t[0]||(t[0]=[l(`<h1 id="工具调用测试" tabindex="-1">工具调用测试 <a class="header-anchor" href="#工具调用测试" aria-label="Permalink to &quot;工具调用测试&quot;">​</a></h1><blockquote><p>TODO: 截图 — 工具主界面，展示四个标签页</p></blockquote><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>工具调用测试（Tool Calling Tester）是一个<strong>内部工具调用系统的调试与验证矩阵</strong>。它让你能够直观地查看系统中所有已注册的工具和方法，在安全的沙盒环境中执行测试调用，验证 LLM 生成的 VCP 格式请求是否能正确解析，并监控异步任务的执行状态。</p><p>简单来说，它是整个 AIO Hub <strong>&quot;工具调用生态&quot;的控制台</strong>——无论你是想了解某个工具提供了什么能力，还是想调试智能体调用工具时出了什么问题，这里都能帮你搞定。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>工具库浏览</strong>：查看系统中所有已注册工具及其可调用的方法、参数列表，支持搜索、筛选和排序</li><li><strong>执行沙盒</strong>：在隔离环境中选择一个工具方法，填写参数（支持表单模式和 JSON 模式），执行并查看完整结果</li><li><strong>解析器验证</strong>：输入包含 VCP 格式请求块的混合文本，一键解析并验证 LLM 生成的工具请求是否正确</li><li><strong>异步任务监控</strong>：实时跟踪所有异步任务的执行状态（排队中、执行中、完成、失败），支持取消、重试和清理</li><li><strong>VCP 指令生成</strong>：从当前选择的工具方法一键生成 VCP 格式的调用指令，方便复制到其他场景测试</li></ul><hr><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="场景一-浏览可用工具-2-分钟" tabindex="-1">场景一：浏览可用工具（2 分钟） <a class="header-anchor" href="#场景一-浏览可用工具-2-分钟" aria-label="Permalink to &quot;场景一：浏览可用工具（2 分钟）&quot;">​</a></h3><p>打开工具后，默认进入 <strong>工具库浏览</strong> 标签页。这里以卡片网格的形式展示系统内所有已注册的工具。</p><blockquote><p>TODO: 截图 — 工具库浏览页面，展示工具卡片网格</p></blockquote><ol><li><strong>查看工具详情</strong>：点击任意工具卡片，右侧展开详情的侧边栏，显示该工具下所有可调用的方法。</li><li><strong>搜索工具</strong>：在顶部搜索框输入工具名称或方法名称，实时过滤。</li><li><strong>切换排序</strong>：点击「名称 / 数量」按钮，在按名称排序和按方法数量排序之间切换。</li><li><strong>筛选</strong>：点击「筛选」按钮展开筛选面板，可以按执行模式（同步/异步）、工厂类等方式过滤。</li></ol><blockquote><p>TODO: 截图 — 展开筛选面板，展示执行模式、工厂类筛选</p></blockquote><h3 id="场景二-执行一次工具调用-5-分钟" tabindex="-1">场景二：执行一次工具调用（5 分钟） <a class="header-anchor" href="#场景二-执行一次工具调用-5-分钟" aria-label="Permalink to &quot;场景二：执行一次工具调用（5 分钟）&quot;">​</a></h3><p>假设你想测试系统的目录树生成功能：</p><ol><li>切换到 <strong>执行沙盒</strong> 标签页。</li><li>在顶部下拉框中搜索或选择目标方法，例如 <code>directory-tree</code> 组的 <code>generateTree</code>。</li><li>选择方法后，下方会自动加载参数配置区域。默认使用<strong>表单模式</strong>，每个参数都有对应的输入控件： <ul><li><code>path</code>：输入一个目录路径，如 <code>E:\\rc20\\allinweb\\all-in-one-tools\\src</code></li><li><code>maxDepth</code>：设置为 <code>3</code></li><li><code>showFiles</code>：切换开关为 <code>true</code></li><li><code>showHidden</code>：切换开关为 <code>false</code></li></ul></li></ol><blockquote><p>TODO: 截图 — 执行沙盒页面，展示已选方法、参数表单</p></blockquote><ol start="4"><li>点击 <strong>触发调用</strong> 按钮，右侧面板会显示执行结果（包括状态、耗时、返回数据）。</li></ol><blockquote><p>TODO: 截图 — 执行结果面板，展示成功/失败的反馈</p></blockquote><ol start="5"><li>你也可以切换到 <strong>JSON 模式</strong> 直接编辑参数 JSON，适合需要精确控制参数值的场景。</li></ol><h3 id="场景三-验证-llm-解析结果-3-分钟" tabindex="-1">场景三：验证 LLM 解析结果（3 分钟） <a class="header-anchor" href="#场景三-验证-llm-解析结果-3-分钟" aria-label="Permalink to &quot;场景三：验证 LLM 解析结果（3 分钟）&quot;">​</a></h3><p>当你好奇智能体生成的工具调用指令是否正确时，可以使用解析器验证功能：</p><ol><li>切换到 <strong>解析器验证</strong> 标签页。</li><li>左侧编辑器中有一段预填充的示例文本，包含一个 VCP 格式的 <code>[TOOL_REQUEST]</code> 块。</li><li>点击 <strong>运行解析引擎</strong>，右侧会展示解析出的工具请求列表。</li></ol><blockquote><p>TODO: 截图 — 解析器验证页面，左侧输入/右侧结果</p></blockquote><p>每个解析结果卡片都会显示：</p><ul><li><strong>工具名称</strong>：解析出的目标工具</li><li><strong>状态标签</strong>：<code>已就绪</code>（工具存在且方法可调用）、<code>格式错误</code>（VCP 语法出错）、<code>工具不存在</code>（未注册的工具）</li><li><strong>提取参数</strong>：解析出的参数键值对</li></ul><hr><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="_1-工具库浏览-discovery" tabindex="-1">① 工具库浏览（Discovery） <a class="header-anchor" href="#_1-工具库浏览-discovery" aria-label="Permalink to &quot;① 工具库浏览（Discovery）&quot;">​</a></h3><p>这是工具调用系统的&quot;体检中心&quot;，让你一目了然地看到所有工具提供了哪些能力。</p><h4 id="工具卡片网格" tabindex="-1">工具卡片网格 <a class="header-anchor" href="#工具卡片网格" aria-label="Permalink to &quot;工具卡片网格&quot;">​</a></h4><p>每个工具以卡片形式展示：</p><ul><li><strong>图标</strong>：工具注册时的图标</li><li><strong>名称</strong>：工具显示名称</li><li><strong>ID</strong>：工具内部标识符（如 <code>directory-tree</code>、<code>smart-ocr</code>）</li><li><strong>方法数</strong>：该工具下可被智能体调用的方法数量</li><li><strong>工厂标签</strong>：如果工具属于某个工厂类，会显示工厂标签</li></ul><h4 id="详情侧边栏" tabindex="-1">详情侧边栏 <a class="header-anchor" href="#详情侧边栏" aria-label="Permalink to &quot;详情侧边栏&quot;">​</a></h4><p>点击任意卡片，右侧会滑出详情面板，展示该工具下所有方法的详细信息：</p><ul><li><strong>方法名称</strong>：显示名称和标识符</li><li><strong>执行模式</strong>：<code>⚡同步方法</code>（即时返回结果）或 <code>⏳异步方法</code>（返回任务 ID，需后续查询）</li><li><strong>方法描述</strong>：说明方法的用途</li><li><strong>参数列表</strong>：列出所有参数名和类型</li><li><strong>加载至执行沙盒</strong>：点击后自动跳转到执行沙盒页并预填好该方法的参数</li></ul><h4 id="搜索与筛选" tabindex="-1">搜索与筛选 <a class="header-anchor" href="#搜索与筛选" aria-label="Permalink to &quot;搜索与筛选&quot;">​</a></h4><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td><strong>搜索框</strong></td><td>按工具名称、ID 或方法名称搜索，实时过滤</td></tr><tr><td><strong>排除词</strong></td><td>输入关键词后，匹配的工具和方<strong>法会被排除</strong></td></tr><tr><td><strong>排序</strong></td><td>按名称排序 / 按方法数量排序</td></tr><tr><td><strong>执行模式筛选</strong></td><td>全部 / 仅同步方法 / 仅异步方法</td></tr><tr><td><strong>工厂类筛选</strong></td><td>按工厂类分组查看</td></tr><tr><td><strong>刷新库</strong></td><td>手动刷新工具列表（订阅了注册表变更，通常会自动更新）</td></tr></tbody></table><h3 id="_2-执行沙盒-executor" tabindex="-1">② 执行沙盒（Executor） <a class="header-anchor" href="#_2-执行沙盒-executor" aria-label="Permalink to &quot;② 执行沙盒（Executor）&quot;">​</a></h3><p>执行沙盒提供了一个安全的测试环境，让你可以在不经过智能体审批流程的情况下，直接调用任何已注册工具的任意方法。</p><h4 id="方法选择器" tabindex="-1">方法选择器 <a class="header-anchor" href="#方法选择器" aria-label="Permalink to &quot;方法选择器&quot;">​</a></h4><p>顶部下拉选择器分为两组：</p><ul><li><strong>组标签</strong>：工具名称（如 <code>directory-tree</code>、<code>tool-calling</code>）</li><li><strong>选项</strong>：该工具下的方法，显示名称 + 方法标识符（次级文字）</li></ul><p>选择方法后，系统会自动加载该方法的参数定义，并初始化默认值。</p><blockquote><p>TODO: 截图 — 方法选择器下拉菜单</p></blockquote><h4 id="参数配置" tabindex="-1">参数配置 <a class="header-anchor" href="#参数配置" aria-label="Permalink to &quot;参数配置&quot;">​</a></h4><p><strong>表单模式</strong>（默认）：每个参数都有对应的输入控件：</p><ul><li><code>string</code> 类型 → 文本输入框</li><li><code>number</code> 类型 → 数字输入框</li><li><code>boolean</code> 类型 → 开关/勾选框</li><li><code>array</code> / <code>object</code> 类型 → 代码编辑器输入</li></ul><p><strong>JSON 模式</strong>：直接编辑 JSON 格式的参数，适合高级用户或需要传递复杂结构的场景。</p><p>两种模式是<strong>双向同步</strong>的——在表单中修改会自动更新 JSON，在 JSON 中修改也会同步回表单。</p><blockquote><p>TODO: 截图 — 表单模式 vs JSON 模式切换</p></blockquote><h4 id="执行与结果" tabindex="-1">执行与结果 <a class="header-anchor" href="#执行与结果" aria-label="Permalink to &quot;执行与结果&quot;">​</a></h4><ul><li><strong>触发调用</strong>：执行当前配置的工具调用</li><li><strong>生成 VCP</strong>：将当前方法调用生成为 VCP 格式指令并复制到剪贴板</li><li><strong>结果面板</strong>：右侧展示最近 10 条执行记录，每条包含状态标记（成功/失败/被拒绝）、执行耗时和返回数据</li></ul><blockquote><p>TODO: 截图 — 执行结果卡片，展示成功/失败的视觉差异</p></blockquote><h4 id="参数类型自适应" tabindex="-1">参数类型自适应 <a class="header-anchor" href="#参数类型自适应" aria-label="Permalink to &quot;参数类型自适应&quot;">​</a></h4><p>系统会自动根据参数元数据的类型做适配（类型强转），确保字符串形式的 <code>&quot;true&quot;</code> 被转为布尔值 <code>true</code>，数字字符串 <code>&quot;42&quot;</code> 被转为数字 <code>42</code>。这意味着无论是智能体生成的参数还是手动输入，都会被正确处理。</p><h3 id="_3-解析器验证-parser" tabindex="-1">③ 解析器验证（Parser） <a class="header-anchor" href="#_3-解析器验证-parser" aria-label="Permalink to &quot;③ 解析器验证（Parser）&quot;">​</a></h3><p>这个模块专门用于<strong>验证 LLM 回复中的工具调用请求</strong>能否被正确解析。</p><h4 id="vcp-协议格式" tabindex="-1">VCP 协议格式 <a class="header-anchor" href="#vcp-协议格式" aria-label="Permalink to &quot;VCP 协议格式&quot;">​</a></h4><p>工具调用采用 VCP（Verbal Command Protocol）协议格式，在 LLM 的回复文本中用特殊标记包裹：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;&lt;&lt;[TOOL_REQUEST]&gt;&gt;&gt;</span></span>
<span class="line"><span>tool_name:「始」directory-tree「末」,</span></span>
<span class="line"><span>command:「始」generateTree「末」,</span></span>
<span class="line"><span>path:「始」E:\\path「末」,</span></span>
<span class="line"><span>maxDepth:「始」5「末」</span></span>
<span class="line"><span>&lt;&lt;&lt;[END_TOOL_REQUEST]&gt;&gt;&gt;</span></span></code></pre></div><p>解析器可以从混合文本中提取出这些标记块，解析出工具名称、方法名和参数。</p><h4 id="解析结果验证" tabindex="-1">解析结果验证 <a class="header-anchor" href="#解析结果验证" aria-label="Permalink to &quot;解析结果验证&quot;">​</a></h4><p>解析后，每个请求会进行三级验证：</p><ol><li><strong>格式验证</strong>：VCP 语法是否正确（标记完整性、字段格式）</li><li><strong>工具验证</strong>：目标工具是否已在系统中注册</li><li><strong>方法验证</strong>：目标方法是否存在于该工具中且标记为可调用</li></ol><p>验证结果以标签形式展示：</p><ul><li>🟢 <strong>已就绪</strong>：工具和方法都存在，可以正常执行</li><li>🔴 <strong>格式错误</strong>：VCP 语法有问题，点击标签查看详情</li><li>🔴 <strong>工具不存在</strong>：系统中未注册该工具</li></ul><h4 id="典型场景" tabindex="-1">典型场景 <a class="header-anchor" href="#典型场景" aria-label="Permalink to &quot;典型场景&quot;">​</a></h4><p>当你发现智能体没有正确执行工具调用时，可以把 LLM 的完整回复文本粘贴到解析器验证中，检查：</p><ul><li>VCP 格式是否正确（字段名是否匹配）</li><li>工具名称是否拼写正确</li><li>参数名是否与定义的参数列表一致</li></ul><h3 id="_4-异步任务监控-asynctask" tabindex="-1">④ 异步任务监控（AsyncTask） <a class="header-anchor" href="#_4-异步任务监控-asynctask" aria-label="Permalink to &quot;④ 异步任务监控（AsyncTask）&quot;">​</a></h3><p>异步任务监控是一个完整的任务队列管理面板，让你可以实时跟踪所有通过工具调用系统提交的长时间任务。</p><blockquote><p>TODO: 截图 — 异步任务监控完整界面</p></blockquote><h4 id="统计概览" tabindex="-1">统计概览 <a class="header-anchor" href="#统计概览" aria-label="Permalink to &quot;统计概览&quot;">​</a></h4><p>页面顶部的统计栏展示当前任务队列概况：</p><ul><li><strong>总任务</strong>：所有提交过的任务总数</li><li><strong>运行中</strong>：当前正在执行的任务</li><li><strong>已完成</strong>：成功完成的任务</li><li><strong>失败</strong>：执行失败的任务</li></ul><h4 id="任务表格" tabindex="-1">任务表格 <a class="header-anchor" href="#任务表格" aria-label="Permalink to &quot;任务表格&quot;">​</a></h4><p>任务列表以表格形式展示，支持：</p><ul><li><strong>状态筛选</strong>：全部 / 排队中 / 运行中 / 已完成 / 失败</li><li><strong>关键词搜索</strong>：按任务 ID 或工具名称搜索</li><li><strong>自动刷新</strong>：订阅了任务状态变更，实时更新</li></ul><p><strong>任务操作</strong>：</p><table tabindex="0"><thead><tr><th>状态</th><th>可用操作</th></tr></thead><tbody><tr><td>运行中</td><td>取消任务</td></tr><tr><td>已完成</td><td>查看详情</td></tr><tr><td>失败</td><td>查看详情 / 重试任务</td></tr><tr><td>已取消</td><td>重试任务</td></tr></tbody></table><blockquote><p>TODO: 截图 — 任务详情弹窗</p></blockquote><h4 id="批量清理" tabindex="-1">批量清理 <a class="header-anchor" href="#批量清理" aria-label="Permalink to &quot;批量清理&quot;">​</a></h4><ul><li><strong>清理已完成</strong>：一键删除所有已完成的任务</li><li><strong>清理失败</strong>：一键删除所有失败的任务</li><li><strong>清理全部</strong>：清空整个任务队列</li></ul><hr><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="跨工具链路测试" tabindex="-1">跨工具链路测试 <a class="header-anchor" href="#跨工具链路测试" aria-label="Permalink to &quot;跨工具链路测试&quot;">​</a></h3><p>你可以使用工具库浏览功能了解多个工具的能力，然后在执行沙盒中逐个测试它们的方法，验证参数传递和数据返回是否符合预期。这对于调试复杂的多工具协作场景非常有用。</p><h3 id="解析器边界测试" tabindex="-1">解析器边界测试 <a class="header-anchor" href="#解析器边界测试" aria-label="Permalink to &quot;解析器边界测试&quot;">​</a></h3><p>解析器验证支持任意文本输入，你可以在左侧编辑器中构造各种边界情况的 VCP 请求：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ 正常请求：标准格式，所有字段完整</span></span>
<span class="line"><span>⚠️ 缺少字段：不带 tool_name 的请求块</span></span>
<span class="line"><span>❌ 格式错误：标记不完整或字段值格式错误</span></span></code></pre></div><p>这样可以提前发现解析器的处理边界，确保智能体在极端情况下也能稳定工作。</p><h3 id="异步任务压力测试" tabindex="-1">异步任务压力测试 <a class="header-anchor" href="#异步任务压力测试" aria-label="Permalink to &quot;异步任务压力测试&quot;">​</a></h3><p>通过注册表中的 <code>testAsyncTask</code> 方法，你可以提交多个模拟的异步任务（可以控制持续时间和是否失败），然后在异步任务监控中观察它们的执行状态变化、取消操作和重试行为。</p><blockquote><p>TODO: 截图 — 异步任务监控页面的统计卡片和任务列表</p></blockquote><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-执行沙盒中的调用会经过审批流程吗" tabindex="-1">Q：执行沙盒中的调用会经过审批流程吗？ <a class="header-anchor" href="#q-执行沙盒中的调用会经过审批流程吗" aria-label="Permalink to &quot;Q：执行沙盒中的调用会经过审批流程吗？&quot;">​</a></h3><p><strong>A</strong>：不会。执行沙盒直接通过系统内部的 <code>execute</code> 服务调用工具方法，跳过了 LLM 智能体的审批流程。这意味着所有在沙盒中执行的调用都是<strong>立即执行且无需审批</strong>的。这适合开发调试场景，但在生产环境中需要注意操作风险。</p><h3 id="q-解析器验证的结果和实际-llm-解析有什么不同" tabindex="-1">Q：解析器验证的结果和实际 LLM 解析有什么不同？ <a class="header-anchor" href="#q-解析器验证的结果和实际-llm-解析有什么不同" aria-label="Permalink to &quot;Q：解析器验证的结果和实际 LLM 解析有什么不同？&quot;">​</a></h3><p><strong>A</strong>：解析器验证使用的是和 LLM 智能体完全相同的解析引擎（<code>core/parser.ts</code>），所以结果是一致的。你看到的每一个解析结果，都反映了实际智能体在调用工具时的解析效果。区别在于解析器验证没有后续的执行和审批流程。</p><h3 id="q-异步任务的状态是实时更新的吗" tabindex="-1">Q：异步任务的状态是实时更新的吗？ <a class="header-anchor" href="#q-异步任务的状态是实时更新的吗" aria-label="Permalink to &quot;Q：异步任务的状态是实时更新的吗？&quot;">​</a></h3><p><strong>A</strong>：是的。异步任务监控通过 Pinia Store 订阅了任务管理器的状态变更事件，当任何任务的状态发生变化时（排队 → 执行中 → 完成/失败），监控面板会实时更新。你不需要手动刷新页面。</p><h3 id="q-为什么点击-加载至执行沙盒-后-参数显示为空" tabindex="-1">Q：为什么点击&quot;加载至执行沙盒&quot;后，参数显示为空？ <a class="header-anchor" href="#q-为什么点击-加载至执行沙盒-后-参数显示为空" aria-label="Permalink to &quot;Q：为什么点击&quot;加载至执行沙盒&quot;后，参数显示为空？&quot;">​</a></h3><p><strong>A</strong>：可能是该方法的参数定义中没有设置默认值。你可以切换到 <strong>JSON 模式</strong>，手动填入参数 JSON，或先在 <strong>表单模式</strong> 中逐个填写参数值。参数配置支持表单/JSON 双向同步，填写任意一侧都会同步到另一侧。</p><h3 id="q-执行结果提示-方法不存在-或-工具不存在" tabindex="-1">Q：执行结果提示&quot;方法不存在&quot;或&quot;工具不存在&quot;？ <a class="header-anchor" href="#q-执行结果提示-方法不存在-或-工具不存在" aria-label="Permalink to &quot;Q：执行结果提示&quot;方法不存在&quot;或&quot;工具不存在&quot;？&quot;">​</a></h3><p><strong>A</strong>：这可能是因为目标工具虽然在工具库中可见，但其注册的 <code>Registry</code> 实例可能由于某种原因未能正确初始化。请尝试：</p><ol><li>点击 <strong>刷新库</strong> 按钮，确认工具列表已更新</li><li>检查目标工具是否已正确初始化（在工具库浏览中查看工具卡片是否正常显示方法列表）</li><li>如果问题持续，可能是工具注册的 <code>agentCallable</code> 标记未正确设置，请联系开发者</li></ol>`,109)])])}const p=o(r,[["render",n]]);export{u as __pageData,p as default};
